  ('police-b20a8cf8-moex-00194', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '為顯現包覆槍枝的膠帶上潛伏指紋，經檢視該膠帶為非紙質材料，在與槍枝分離後，對該膠帶可 行的正確指紋採證系統處理法為何？', '["先染料漂染，再以氰丙烯酸酯法燻蒸，黏膠面再以粉末懸浮液法處理", "先以粉末懸浮液法採黏膠面，再以氰丙烯酸酯法燻蒸，最後再以染料漂染加強", "先以氰丙烯酸酯法燻蒸，再以染料漂染，黏膠面再以粉末懸浮液法處理", "非黏膠面先以粉末法採驗，黏膠面以染料漂染，最後再以氰丙烯酸酯法燻蒸"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00195', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '為進行恐嚇信件的採證，試圖鑑別出寄信人是誰及以筆跡比對出書寫者，試問較適當的處理方式 為何？', '["為避免污染先採驗DNA，再以寧海德林法採驗指紋，最後進行文書鑑定", "先保護信件避免污染，再以高畫素掃描文書證物，以寧海德林法採驗指紋，再採驗 DNA，最 後進行文書鑑定", "以高畫素掃描文書證物後，為避免污染先採驗 DNA，再以寧海德林法採驗指紋，最後進行文 書鑑定", "為避免污染先採驗DNA，再進行文書採證鑑定後，最後以寧海德林法採驗指紋"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00196', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '以Kastle-Meyer試劑進行血跡檢測時，其試驗係以血跡中的何種成分為檢測標的？又該試劑酸鹼 特性為何？', '["血紅蛋白血基質的過氧化酶活性，鹼性", "血紅蛋白血基質的過氧化酶活性，酸性", "血漿蛋白的磷酸酶，鹼性", "血漿蛋白的磷酸酶，酸性"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00197', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '重大事故現場罹難者檢體DNA鑑定結果，編號1罹難者檢體Y染色體DNA未檢出，編號2與 編號3罹難者檢體Y染色體DNA均檢出，且檢出之27組Y-STRDNA 型別均相同，編號1、3 罹難者檢體粒線體DNAHV1、HV2型別均相同，三人體染色體DNA-STR檢出21組型別中，編 號1與2檢體有3組型別相同、5組有一個對偶基因型相同、13組型別不同，編號1與3檢體 21組均至少有一個對偶基因型相同，編號2與3檢體21組均至少有一個對偶基因型相同，依此 檢測結果，研判三者血緣關係依序可能為下列何者？', '["女兒、父親、兒子", "母親、父親、兒子", "母親、兒子、兒子", "祖母（母親的母親）、兒子、父親"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00198', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '以免疫層析法檢測是否為人血，當人血抗原濃度過高時，可能會有下列何種反應？', '["Hookeffect，偽陰性反應", "Falsepositive，偽陽性反應", "Cross-reactivity，交叉反應", "Highdefect，高缺失反應"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00199', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '由刑案現場採取之不同編號生物跡證，經以即時聚合酶連鎖反應（Real-TimePCR）檢測人類DNA 含量，檢測結果以檢量線Ct值（Cycle Threshold Value）換算人類DNA濃度。檢測結果：編號 1Ct 值為26.58，編號2Ct值為28.21，編號3Ct值為22.27，編號4Ct值為22.75，請問所測人 類DNA濃度由高至低依序排列編號為何？', '["2、1、4、3", "3、4、1、2", "3、1、4、2", "2、3、4、1"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00200', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '在疑似製造毒品案件現場中，發現有多包鹽酸羥亞胺（hydroxylimine），請問涉嫌人意圖製造何 種毒品？ 現場應尋找何種設備以佐證為其製毒所需？', '["甲基安非他命，冷凝管與冷卻設備", "K他命，冷凝管與冷卻設備", "K他命，加熱設備", "4-甲基甲基卡西酮，攪拌設備"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00201', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '槍擊案件現場彈殼採證與比對很重要，下列相關彈殼比對之敘述何者不正確？', '["抓子痕，為自動退殼槍枝抓子鉤在彈殼底部凹槽及邊緣所留下之工具痕跡，具分類價值", "彈殼底火部位撞針痕，其形狀與位置與槍枝廠牌形式有關，具分類及個化價值", "彈底紋，為擊發時撞擊槍後膛壁所形成之工具痕跡，具分類及個化價值", "退子痕，具研判射擊槍枝的分類價值，轉輪槍射擊的彈殼此痕跡特別明顯"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00202', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '為顯現具複雜圖案之鈔票上潛伏指紋，先在鈔票上刷掃反斯托克斯粉末（anti-strokespowder）， 接著再進行指紋發光攝影，下列那一項對於此類潛伏指紋發光攝影之描述最適當﹖', '["先使用紫外光進行指紋之激發而發出可見光，再進行可見光之攝影", "先使用可見光進行指紋之激發而發出紅外光，再進行紅外光之攝影", "先使用紅外光進行指紋之激發而發出可見光，再進行可見光之攝影", "先使用紫外光進行指紋之激發而發出紅外光，再進行紅外光之攝影"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00203', 'police-b20a8cf8', 'police-b20a8cf8-moex-113-585f428e', 'sub-police-b20a8cf8-03', NULL, 'single_choice', '下列那些體液斑因具有發光性，進行現場勘察時可在昏暗環境下，選用適當光源搜尋出體液之位', '["血液斑", "精液斑", "唾液斑", "尿液斑  ⑤汗液斑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:22+00:00", "source_pdf_sha1": "13394bfc98b1", "answer_pdf_sha1": "d03988d172d3", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "503", "s": "1401", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "刑案現場處理與刑事鑑識", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
